import Vue from 'vue';
import App from './App.vue';
import router from './router';
// 公共样式文件引入
import '@/styles/common.scss';
// element-ui
import ElementUI from 'element-ui';
import 'element-ui/lib/theme-chalk/index.css';
// 引入axios库
import axios from 'axios';
Vue.prototype.$axios = axios;
// 引入qs库
import qs from 'qs';
Vue.prototype.$QS = qs;
Vue.config.productionTip = false;
Vue.use(ElementUI);
// 立图UI组件库
import LTUIPro from '/packages/LTUIPro'  // 引入组件库
import '/packages/LTUIPro/dist/LTUIPro.css' // 引入样式库
Vue.use(LTUIPro);
// 引入vue-seamless-scroll
import scroll from 'vue-seamless-scroll';
Vue.use(scroll);
import hljsVuePlugin from '@highlightjs/vue-plugin'
import hljs from 'highlight.js'
// 关键：导入Highlight.js浅色主题（示例用Atom One Light，可替换为上表其他主题）
import 'highlight.js/styles/atom-one-light.css'
Vue.use(hljsVuePlugin);
import codeCopy from "@/components/code.vue"
Vue.component('codeCopy', codeCopy);
new Vue({
  router,
  render: (h) => h(App),
}).$mount('#app');
