<template>
  <div id="codeView"  style="position: relative;padding-top: 15px;">
    <div class="code-title">{{title}}</div>
    <div title="复制代码" style="color:#fff;" class="copy-icon icon zhb-iconfont zhb-iconfuzhi" @click="copyCode()"></div>
    <highlightjs language="JavaScript" :autodetect="false" :code="code"></highlightjs>
    <input :id="id" type="text" :value="code" style="opacity: 0">
  </div>
</template>

<script>

export default {
  name: 'Code',
  props: {
    code: {
      type: [Object, String],
      default: function() {
        return {};
      }
    },
    id: {
      type: [Object, String],
      default: function() {
        return {};
      }
    },
    title: {
      type: String,
      default: ''
    }
  },
  methods: {
    copyCode() {
      var copyObject = document.getElementById(this.id);
      copyObject.select();
      document.execCommand('Copy');
      this.$message.success("复制成功！");
    }
  }
}
</script>

<style lang="scss">
.code-title {
  font-size: 14px;
  position: absolute;
  top:0;
  left: 0;
  color:#fff;
  font-weight: bold;
}
pre code.hljs {
  font-size: 18px!important;
  border-radius: 8px!important;
}

.copy-icon {
  position: absolute;
  top: 0px;
  right: 0px;
  cursor: pointer;
}
</style>
